ALTER TABLE transaction_city_merge
  ADD COLUMN new_city_lat varchar(100) CHARACTER SET utf8 COLLATE utf8_unicode_ci DEFAULT NULL AFTER old_city_url,
  ADD COLUMN new_city_lng varchar(100) CHARACTER SET utf8 COLLATE utf8_unicode_ci DEFAULT NULL AFTER new_city_lat,
  ADD COLUMN old_city_lat varchar(100) CHARACTER SET utf8 COLLATE utf8_unicode_ci DEFAULT NULL AFTER new_city_lng,
  ADD COLUMN old_city_lng varchar(100) CHARACTER SET utf8 COLLATE utf8_unicode_ci DEFAULT NULL AFTER old_city_lat;
ON DUPLICATE KEY UPDATE
  new_city_id = VALUES(new_city_id),
  new_city_parent_id = VALUES(new_city_parent_id),
  old_city_parent_id = VALUES(old_city_parent_id),
  old_district_id = VALUES(old_district_id),
  new_city_name = VALUES(new_city_name),
  old_city_name = VALUES(old_city_name),
  new_city_url = VALUES(new_city_url),
  old_city_url = VALUES(old_city_url),
  new_city_lat = VALUES(new_city_lat),
  new_city_lng = VALUES(new_city_lng),
  old_city_lat = VALUES(old_city_lat),
  old_city_lng = VALUES(old_city_lng),
  action_type = VALUES(action_type),
  redirect = VALUES(redirect);
